import face_recognition
import numpy as np
from collections import defaultdict
import os

# --- Configuration ---
# Threshold for considering a face a "match".
# Distances are typically low for matches (e.g., < 0.6 for face_recognition default).
# Adjust based on your dataset and desired strictness.
FACE_MATCH_THRESHOLD = 0.6

# --- Data Storage (In a real system, this would be a secure database) ---
KNOWN_FACE_ENCODINGS = []
KNOWN_FACE_NAMES = []
# Map names to their individual embeddings (if multiple photos per person)
NAME_TO_ENCODINGS_MAP = defaultdict(list)

# --- Model Training Function ---
def train_model(employee_photos_dir="employee_photos"):
    """
    Trains the "model" by loading employee photos, extracting face encodings,
    and storing them for future comparison.

    Args:
        employee_photos_dir (str): Path to the directory containing subdirectories
                                   for each employee, where each subdirectory
                                   contains photos of that employee.
                                   Example structure:
                                   employee_photos/
                                   ├── alice/
                                   │   ├── alice_1.jpg
                                   │   └── alice_2.png
                                   └── bob/
                                       ├── bob_photo.jpeg
                                       └── bob_selfie.jpg
    """
    print(f"--- Starting training on photos in '{employee_photos_dir}' ---")
    global KNOWN_FACE_ENCODINGS, KNOWN_FACE_NAMES, NAME_TO_ENCODINGS_MAP
    KNOWN_FACE_ENCODINGS = []
    KNOWN_FACE_NAMES = []
    NAME_TO_ENCODINGS_MAP = defaultdict(list)

    if not os.path.exists(employee_photos_dir):
        print(f"Error: Employee photos directory '{employee_photos_dir}' not found.")
        print("Please create it and place employee photo subdirectories inside.")
        return

    for person_name in os.listdir(employee_photos_dir):
        person_dir = os.path.join(employee_photos_dir, person_name)
        if not os.path.isdir(person_dir):
            continue

        print(f"Processing employee: {person_name}")
        for filename in os.listdir(person_dir):
            if filename.lower().endswith(('.png', '.jpg', '.jpeg', '.gif', '.bmp')):
                image_path = os.path.join(person_dir, filename)
                try:
                    image = face_recognition.load_image_file(image_path)
                    face_locations = face_recognition.face_locations(image)
                    if len(face_locations) == 0:
                        print(f"  Warning: No face found in {filename} for {person_name}")
                        continue
                    if len(face_locations) > 1:
                        print(f"  Warning: Multiple faces found in {filename} for {person_name}. Using the first one.")

                    # Get the first face encoding
                    face_encoding = face_recognition.face_encodings(image, known_face_locations=[face_locations[0]])[0]

                    NAME_TO_ENCODINGS_MAP[person_name].append(face_encoding)
                    print(f"  Added encoding from {filename}")

                except Exception as e:
                    print(f"  Error processing {filename} for {person_name}: {e}")
                    continue
    
    # Flatten the map into global lists for use with face_recognition.face_distance
    for name, encodings in NAME_TO_ENCODINGS_MAP.items():
        KNOWN_FACE_ENCODINGS.extend(encodings)
        KNOWN_FACE_NAMES.extend([name] * len(encodings)) # Each encoding gets its name

    print(f"--- Training complete. Loaded {len(KNOWN_FACE_ENCODINGS)} face encodings for {len(set(KNOWN_FACE_NAMES))} unique employees. ---")
    if not KNOWN_FACE_ENCODINGS:
        print("No employee faces were successfully loaded for training.")


# --- API Endpoint Function ---
def recognize_faces_api(image_bytes: bytes):
    """
    API endpoint function to recognize faces in an input image.

    Args:
        image_bytes (bytes): The bytes of the image file to analyze.

    Returns:
        list: A list of dictionaries, where each dictionary represents a detected
              face and its recognition results. Each dictionary contains:
              - "face_location": Tuple (top, right, bottom, left) of the face.
              - "top_match": Name of the employee with the highest confidence.
              - "confidence_score": A score (0.0 to 1.0) indicating how confident
                                    the system is about the top match. This score
                                    is related to the minimum distance to a known face.
              - "detailed_probability_distribution": A dictionary mapping
                                                     employee names to their
                                                     "probability" of being
                                                     the detected face.
                                                     These probabilities sum to 1.0.
              - "is_known_employee": True if a match was found above threshold, False otherwise.
    """
    if not KNOWN_FACE_ENCODINGS:
        return [{"error": "Model not trained. Please call train_model() first."}]

    try:
        # Convert image bytes to a numpy array
        image = face_recognition.load_image_file(image_bytes)
    except Exception as e:
        return [{"error": f"Failed to load image from bytes: {e}"}]

    # Find all face locations and face encodings in the current frame of video
    face_locations = face_recognition.face_locations(image)
    face_encodings = face_recognition.face_encodings(image, face_locations)

    results = []

    for (top, right, bottom, left), face_encoding in zip(face_locations, face_encodings):
        face_result = {
            "face_location": (top, right, bottom, left),
            "top_match": "Unknown",
            "confidence_score": 0.0,
            "detailed_probability_distribution": {},
            "is_known_employee": False
        }

        if not KNOWN_FACE_ENCODINGS:
            results.append(face_result)
            continue

        # Calculate distances to all known faces
        face_distances = face_recognition.face_distance(KNOWN_FACE_ENCODINGS, face_encoding)

        # Map minimum distances back to unique employee names
        # If an employee has multiple encodings, we take the minimum distance (best match)
        employee_min_distances = defaultdict(lambda: float('inf'))
        for i, name in enumerate(KNOWN_FACE_NAMES):
            employee_min_distances[name] = min(employee_min_distances[name], face_distances[i])

        unique_employee_names = sorted(list(set(KNOWN_FACE_NAMES))) # Sort for consistent output order
        
        if not unique_employee_names:
            results.append(face_result)
            continue

        unique_employee_distances = [employee_min_distances[name] for name in unique_employee_names]
        
        # Convert distances to "raw scores" for probability distribution.
        # Smaller distance means higher score. Use 1/(1+distance) or similar.
        # Adding a small constant in the denominator prevents division by zero
        # and smooths scores for very small distances.
        raw_scores = [1 / (1 + d) for d in unique_employee_distances]
        
        # Apply softmax to get a probability distribution
        # Subtract max for numerical stability with large negative exponents
        if np.sum(raw_scores) > 1e-9: # Check if there's any significant similarity
            exp_scores = np.exp(raw_scores - np.max(raw_scores))
            sum_exp_scores = np.sum(exp_scores)
            probabilities = exp_scores / sum_exp_scores
        else:
            # If all scores are effectively zero, uniform distribution among known faces
            # or all zeros if no known faces
            probabilities = np.zeros(len(unique_employee_names))
            if len(unique_employee_names) > 0:
                probabilities = np.full(len(unique_employee_names), 1.0 / len(unique_employee_names))
            
        
        detailed_prob_dist = {name: prob for name, prob in zip(unique_employee_names, probabilities)}
        
        # Find the best match among unique employees based on the highest probability
        best_match_index = np.argmax(probabilities)
        top_match_name = unique_employee_names[best_match_index]
        
        # Determine if it's a "known" employee based on the direct minimum distance threshold
        min_overall_distance = np.min(face_distances) # min distance to *any* known encoding
        is_match = min_overall_distance < FACE_MATCH_THRESHOLD

        if is_match:
            face_result["top_match"] = top_match_name
            # Confidence score can be 1.0 for a perfect match (0 distance) and
            # decrease as distance approaches FACE_MATCH_THRESHOLD, becoming 0 at or beyond it.
            face_result["confidence_score"] = max(0.0, 1.0 - (min_overall_distance / FACE_MATCH_THRESHOLD))
            face_result["is_known_employee"] = True
        else:
            # If not a match, confidence is effectively 0 for a *known employee*,
            # even if there's a highest probability towards one.
            face_result["confidence_score"] = 0.0
            face_result["top_match"] = "Unknown" # Explicitly set to Unknown if not within threshold

        face_result["detailed_probability_distribution"] = detailed_prob_dist
        results.append(face_result)

    return results

